package com.infy.inventrack.user; import com.infy.inventrack.common.dto.UserRegistrationRequest; import com.infy.inventrack.common.enums.UserRole; import com.infy.inventrack.common.exception.DuplicateResourceException; import com.infy.inventrack.user.entity.AppUser; import com.infy.inventrack.user.repository.UserRepository; import com.infy.inventrack.user.service.UserService; import org.junit.jupiter.api.Test; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import static org.assertj.core.api.Assertions.*; import static org.mockito.ArgumentMatchers.any; import static org.mockito.Mockito.*; class UserServiceTest { UserRepository repo=mock(UserRepository.class); UserService service=new UserService(repo,new BCryptPasswordEncoder()); @Test void duplicateRejected(){ when(repo.existsByUserNameIgnoreCase("john_doe")).thenReturn(true); assertThatThrownBy(()->service.registerUser(req())).isInstanceOf(DuplicateResourceException.class); } @Test void registerReturnsUser(){ when(repo.save(any(AppUser.class))).thenAnswer(i->{AppUser u=i.getArgument(0); u.setUserId(1); return u;}); assertThat(service.registerUser(req()).getUserName()).isEqualTo("john_doe"); } UserRegistrationRequest req(){ UserRegistrationRequest r=new UserRegistrationRequest(); r.setUserName("john_doe"); r.setPassword("Strong@123"); r.setEmail("john@example.com"); r.setRole(UserRole.CUSTOMER); return r; } }
